/**
 * HyperRealRenderer — real streaming photoreal human interviewer.
 *
 * NO CSS/ SVG fakes. Real head/eye/hand/face motion is generated by the model
 * and arrives over the stream for free. We only:
 *   (1) connect a real stream into the existing <video id="duixVideo">,
 *   (2) delete the orb + any cartoon fallback from the DOM,
 *   (3) interrupt the human the instant the candidate speaks (barge-in),
 *   (4) forward LLM [[gesture:x]]/[[emotion:y]] tags as real model commands,
 *   (5) show a photoreal idle loop while connecting / if the stream drops.
 *
 * Provider is chosen by AVATAR_PROVIDER. HeyGen is wired concretely because its
 * SDK hands us a MediaStream we drop straight into your existing <video>.
 * Tavus / D-ID / self-host implement the SAME adapter shape (swap one object).
 */
const HyperRealRenderer = (function () {
  'use strict';

  // ── Config ────────────────────────────────────────────────────────
  const AVATAR_PROVIDER = 'heygen';                 // 'heygen' | 'tavus' | 'did' | 'selfhost'
  const SESSION_API     = '/api/avatar/session';    // YOUR backend mints the token (key stays server-side)
  const IDLE_LOOP_SRC   = 'assets/ai-interviewer-avatar.png'; // REAL clip/poster of the SAME persona
  const IDLE_POSTER     = 'assets/ai-interviewer-avatar.png';

  // ── DOM (ids taken from your actual page) ─────────────────────────
  const $ = (id) => document.getElementById(id);
  let stageEl, videoEl, captionEl, orbEl, idleEl, configPanelEl;

  // ── State ─────────────────────────────────────────────────────────
  let currentState = 'idle';
  let destroyed = false;
  let adapter = null;          // the provider adapter (below)
  let streamReady = false;
  let abortCtrl = null;
  let captionAnimId = null;

  // ── Inline semantic-tag protocol ──────────────────────────────────
  const TAG_RE = /\[\[(gesture|emotion):([a-z_]+)\]\]/gi;
  function emitAndClean(text) {
    let m;
    while ((m = TAG_RE.exec(text)) !== null) {
      if (!streamReady || !adapter) continue;
      const [, kind, val] = m;
      if (kind === 'gesture' && typeof adapter.triggerGesture === 'function') adapter.triggerGesture(val);
      else if (kind === 'emotion' && typeof adapter.setExpression === 'function') adapter.setExpression(val);
    }
    return text.replace(TAG_RE, '').trim();
  }

  // ═══════════════════════════════════════════════════════════════════
  //  ADAPTER CONTRACT  — every provider implements exactly this.
  //  onReady(MediaStream)  → we attach it to <video>.
  //  onTalkStart/onTalkEnd → caption + state sync.
  //  onTranscript(words)   → word-level captions (real, from the model).
  // ═══════════════════════════════════════════════════════════════════

  // ── HEYGEN (concrete) ─────────────────────────────────────────────
  const HeyGenAdapter = {
    sa: null,
    async connect(videoEl, hooks) {
      // SDK is ESM; dynamic import so the page still loads if not installed.
      let mod;
      try { mod = await import('https://cdn.jsdelivr.net/npm/@heygen/streaming-avatar@2.0.4/+esm'); }
      catch (e) {
        try { mod = await import('@heygen/streaming-avatar'); }
        catch (e2) { throw new Error('PKG_MISSING:@heygen/streaming-avatar'); }
      }
      const StreamingAvatar = mod.default || mod.StreamingAvatar;
      const StreamingAvatarEvents = mod.StreamingAvatarEvents || {};

      // Token from OUR backend (API key never leaves the server).
      const r = await fetch(SESSION_API + '/heygen', { method: 'POST', signal: abortCtrl ? abortCtrl.signal : undefined });
      if (!r.ok) throw new Error('session ' + r.status);
      const { token, avatarName, voiceId } = await r.json();

      this.sa = new StreamingAvatar({ token });
      if (StreamingAvatarEvents.StreamReady) {
        this.sa.on(StreamingAvatarEvents.StreamReady, (e) => {
          if (e?.detail?.stream) {
            videoEl.srcObject = e.detail.stream;     // ← the real human lands here
            hooks.onReady();
          }
        });
      }
      if (StreamingAvatarEvents.AvatarStartTalking) {
        this.sa.on(StreamingAvatarEvents.AvatarStartTalking, () => hooks.onTalkStart());
      }
      if (StreamingAvatarEvents.AvatarEndTalking) {
        this.sa.on(StreamingAvatarEvents.AvatarEndTalking,   () => hooks.onTalkEnd());
      }
      // Word timestamps if the SDK version emits them:
      this.sa.on('avatarTalkText', (e) => {
        if (e?.detail?.words) hooks.onTranscript(e.detail.words);
      });

      await this.sa.createAvatar({ avatarName: avatarName || 'Ann_Doctor_Standing2_public', voice: { voiceId: voiceId || '265511f088344783b38c644837582b9a' } });
      await this.sa.startSession();
    },
    speak(text)        { this.sa?.speak?.({ text }) ?? this.sa?.sendText?.({ text }); },
    interrupt()        { try { this.sa?.interruptSpeaking?.() ?? this.sa?.interrupt?.(); } catch(_) {} },
    setExpression(e)   { try { this.sa?.setEmotion?.(e); } catch(_) {} },
    triggerGesture(g)  { try { this.sa?.sendGesture?.({ gestureName: g }); } catch(_) {} },
    async close()      { try { await this.sa?.endSession?.(); } catch (_) {} this.sa = null; },
  };

  // ── TAVUS / D-ID / SELF-HOST ──────────────────────────────────────
  const TavusAdapter    = {
    async connect(videoEl, hooks) { throw new Error('Tavus adapter requires TAVUS_API_KEY on server'); },
    speak(text) {}, interrupt() {}, setExpression(e) {}, triggerGesture(g) {}, async close() {}
  };
  const DIdAdapter      = {
    async connect(videoEl, hooks) { throw new Error('D-ID adapter requires DID_API_KEY on server'); },
    speak(text) {}, interrupt() {}, setExpression(e) {}, triggerGesture(g) {}, async close() {}
  };
  const SelfHostAdapter = {
    async connect(videoEl, hooks) { throw new Error('SelfHost adapter requires WebRTC server endpoint'); },
    speak(text) {}, interrupt() {}, setExpression(e) {}, triggerGesture(g) {}, async close() {}
  };

  const ADAPTERS = { heygen: HeyGenAdapter, tavus: TavusAdapter, did: DIdAdapter, selfhost: SelfHostAdapter };

  // ═══════════════════════════════════════════════════════════════════
  //  PHOTOREAL IDLE LOOP — a REAL human during "Connecting…" / dropouts
  // ═══════════════════════════════════════════════════════════════════
  function buildIdle() {
    if (idleEl) return;
    idleEl = document.createElement('video');
    idleEl.className = 'hr-idle';
    idleEl.src = IDLE_LOOP_SRC; idleEl.poster = IDLE_POSTER;
    idleEl.muted = true; idleEl.playsInline = true; idleEl.autoplay = true; idleEl.loop = true;
    const frame = stageEl.querySelector('.avatar-frame') || stageEl;
    frame.appendChild(idleEl);
    idleEl.play().catch(() => {});
  }
  const showIdle = (on) => { if (idleEl) idleEl.style.opacity = on ? '1' : '0'; };

  // ═══════════════════════════════════════════════════════════════════
  //  HONEST DEGRADATION — if the real stream can't start, we show a
  //  CONFIG panel, NEVER a cartoon. The truth on screen, not a disguise.
  // ═══════════════════════════════════════════════════════════════════
  function showConfigPanel(reason) {
    if (configPanelEl) configPanelEl.remove();
    configPanelEl = document.createElement('div');
    configPanelEl.className = 'hr-config';
    configPanelEl.innerHTML = `
      <h3>Real human avatar server notice</h3>
      <p>${esc(reason)}</p>
      <ol style="margin-top:10px;padding-left:18px;line-height:1.6">
        <li>Set <code>HEYGEN_API_KEY</code> on your backend server.</li>
        <li>Ensure <code>/api/avatar/session/heygen</code> endpoint is running.</li>
        <li>For production streaming, package <code>@heygen/streaming-avatar</code>.</li>
      </ol>`;
    const frame = stageEl.querySelector('.avatar-frame') || stageEl;
    frame.appendChild(configPanelEl);
  }

  // ═══════════════════════════════════════════════════════════════════
  //  CAPTIONS (word-level when the model provides them)
  // ═══════════════════════════════════════════════════════════════════
  function startCaptions(words) {
    if (!captionEl || !words?.length) return;
    const t0 = performance.now();
    captionEl.innerHTML = words.map((w) => `<span class="duix-word">${esc(w.w)}</span> `).join('');
    captionEl.style.opacity = '1';
    const tick = () => {
      if (destroyed) return;
      const e = performance.now() - t0;
      captionEl.querySelectorAll('.duix-word').forEach((sp, i) => {
        const cw = words[i]; if (!cw) return;
        sp.classList.toggle('active', e >= cw.start && e <= cw.start + cw.dur);
        sp.classList.toggle('spoken', e > cw.start + cw.dur);
      });
      const last = words[words.length - 1];
      captionAnimId = (e < last.start + last.dur + 600) ? requestAnimationFrame(tick) : null;
    };
    captionAnimId = requestAnimationFrame(tick);
  }
  function stopCaptions() { if (captionAnimId) cancelAnimationFrame(captionAnimId); }
  const esc = (s) => { const d = document.createElement('div'); d.textContent = s || ''; return d.innerHTML; };

  // ═══════════════════════════════════════════════════════════════════
  //  STATE → real model behaviour
  // ═══════════════════════════════════════════════════════════════════
  function applyState(s) {
    if (!streamReady || !adapter) return;
    if (s === 'listening')                 { adapter.setExpression('attentive'); adapter.triggerGesture('nod'); }
    else if (s === 'thinking' || s === 'processing') { adapter.setExpression('curious'); adapter.triggerGesture('gaze_away'); }
    else if (s === 'speaking')             { adapter.setExpression('neutral'); }
  }
  function setState(s) {
    if (currentState === s) return;
    currentState = s;
    if (stageEl) {
      stageEl.className = 'avatar-stage hr ' + s;     // 'hr' class = video-card shape
    }
    applyState(s);
  }

  // ═══════════════════════════════════════════════════════════════════
  //  PUBLIC API
  // ═══════════════════════════════════════════
  return {
    async init() {
      destroyed = false; abortCtrl = new AbortController();
      stageEl   = $('avatar-stage');
      videoEl   = $('duixVideo');
      captionEl = $('duix-captions');
      orbEl     = $('ai-avatar-canvas');

      // ── KILL THE FAKES. ──────────────────────────────────────────
      if (orbEl) orbEl.style.display = 'none';                       // no orb
      document.querySelectorAll('.audio-waveform, #waveform, .orb-waveform')
              .forEach((el) => (el.style.display = 'none'));
      const cartoon = $('duix-fallback-face'); if (cartoon) cartoon.remove(); // no SVG

      // ── Real-human stage = video CARD ─────────────────────────────
      if (stageEl) stageEl.classList.add('hr');
      if (stageEl && !stageEl.querySelector('.avatar-frame')) {
        const f = document.createElement('div'); f.className = 'avatar-frame';
        if (videoEl) f.appendChild(videoEl);
        stageEl.prepend(f);
      }
      if (videoEl) {
        videoEl.style.display = 'block'; videoEl.style.opacity = '0';
        videoEl.setAttribute('playsinline', '');
      }

      buildIdle(); showIdle(true);   // a REAL human during "Connecting…"

      // ── Connect the real stream ───────────────────────────────────
      adapter = Object.create(ADAPTERS[AVATAR_PROVIDER] || HeyGenAdapter);
      try {
        await adapter.connect(videoEl, {
          onReady: () => {
            streamReady = true;
            if (videoEl) { videoEl.style.transition = 'opacity .5s ease'; videoEl.style.opacity = '1'; }
            showIdle(false); applyState(currentState);
          },
          onTalkStart: () => { if (stageEl) stageEl.classList.add('speaking'); },
          onTalkEnd:   () => { if (stageEl) stageEl.classList.remove('speaking'); stopCaptions(); },
          onTranscript:(words) => startCaptions(words),
        });
      } catch (e) {
        console.error('[HyperReal] no real stream:', e.message);
        streamReady = false; showIdle(true);
        if (e.message.startsWith('PKG_MISSING')) showConfigPanel('Avatar SDK not installed.');
        else if (/session|401|403/.test(e.message)) showConfigPanel('Avatar API key missing/invalid on server.');
        else showConfigPanel('Stream connect info: ' + e.message);
      }

      setState(currentState || 'idle');
      return 'hyperreal';
    },

    mode() { return 'hyperreal'; },
    getState() { return currentState; },
    onState(s) {
      // BARGE-IN: candidate starts talking → human stops mid-word + attends.
      if (s === 'listening' && streamReady && adapter) adapter.interrupt();
      setState(s);
    },

    say(text) {
      const clean = emitAndClean(text);
      if (streamReady && adapter) {
        adapter.speak(clean);
        if (videoEl) videoEl.style.opacity = '1';
        showIdle(false);
      } else if (typeof DuixRenderer !== 'undefined' && DuixRenderer.isActive()) {
        DuixRenderer.say(clean);
      }
      return Promise.resolve();
    },

    primeCache() { /* streaming model needs no client cache */ },
    setCaptions(text, words) { words?.length ? startCaptions(words)
      : captionEl && (captionEl.textContent = text, captionEl.style.opacity = '1'); },
    feedAudio() { /* duplex audio goes to the model via SDK */ },

    destroy() {
      destroyed = true; stopCaptions();
      if (adapter && typeof adapter.close === 'function') adapter.close();
      if (abortCtrl) abortCtrl.abort();
      if (idleEl) { try { idleEl.pause(); idleEl.src = ''; } catch (_) {} }
      if (videoEl) { try { videoEl.pause(); } catch (_) {} videoEl.srcObject = null; }
    },
    isActive() { return !destroyed; },
  };
})();
